"use strict";parserFactory.register("flying-lines.com",()=>new FlyingLinesParser);class FlyingLinesParser extends Parser{constructor(){super()}getChapterUrls(e){let t=e.querySelector("div.chapter-container");return Promise.resolve(util.hyperlinksToChapterList(t))}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.querySelector("div.title h2")}extractAuthor(e){let t=e.querySelector("ul.profile li");return null===t?super.extractAuthor(e):(util.removeChildElementsMatchingSelector(t,"span"),t.textContent)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.novel-thumb")}fetchChapter(e){return HttpClient.wrapFetch(e).then(function(e){let t=FlyingLinesParser.extractRestUrl(e.responseXML);return HttpClient.fetchJson(t)}).then(function(e){return FlyingLinesParser.buildChapter(e.json.data)})}static extractRestUrl(e){return`https://www.flying-lines.com/chapter/${e.querySelector("div.main_body").getAttribute("data-chapter-id")}`}static buildChapter(e){let t="https://www.flying-lines.com"+e.path,r=Parser.makeEmptyDocForContent(t),n=r.dom.createElement("h1");n.textContent=`${e.chapter_number}. ${e.chapter_title}`,r.content.appendChild(n);let i=util.sanitize(e.chapter_content);for(let e of[...i.body.childNodes])"siteCopyrightInfo"!==e.className&&r.content.appendChild(e);return r.dom}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.novel-info, div.synopsis-detail")]}}